class SiteFooter extends HTMLElement{connectedCallback(){const e=window.location.pathname.includes("/pages/"),t=e?"about.html":"pages/about.html",n=e?"contact.html":"pages/contact.html";this.innerHTML=`\n      <footer class="site-footer" role="contentinfo">\n        <div class="container">\n          <p>© ${(new Date).getFullYear()} DB for WebDev. Учебный проект по предмету "Технологии разработки интернет-приложений".</p>\n          <nav aria-label="Дополнительные ссылки">\n            <a href="${t}">О проекте</a> |\n            <a href="${n}">Контакты</a>\n          </nav>\n        </div>\n      </footer>\n    `}}customElements.define("site-footer",SiteFooter);